namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A", "Warehouse 1", new DateTime(2026, 3, 12)),
            new(2, "Conveyor Belt B", "Warehouse 2", new DateTime(2026, 4, 5)),
            new(3, "Pallet Jack C", "Warehouse 1", new DateTime(2026, 1, 20)),
            new(4, "Crane D", "Yard", new DateTime(2025, 11, 8)),
            new(5, "Compressor E", "Maintenance Bay", new DateTime(2026, 5, 1)),
            new(6, "Welder F", "Shop Floor", new DateTime(2026, 2, 14)),
            new(7, "Drill Press G", "Shop Floor", new DateTime(2025, 12, 30)),
            new(8, "Generator H", "Yard", new DateTime(2026, 4, 22)),
        };
    }
}

@page "/inventory"
@implements IDisposable
@inject IEquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@rendermode InteractiveServer

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? equipment;
    private PersistingComponentStateSubscription persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (!ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            // First render (prerender): fetch from service
            equipment = await EquipmentService.GetEquipmentAsync();
        }
        else
        {
            // Interactive render: reuse persisted data — no second fetch
            equipment = restored;
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
    }
}

